const WebSocket = require('ws');
const token = '51748841efb6483a638b07d7d96d61678bd8619b7cbb8e86';
const ws = new WebSocket('ws://localhost:37249', {
  headers: {
    'Authorization': 'Bearer ' + token
  }
});

ws.on('open', () => {
  console.log('Connected');
});

ws.on('message', (data) => {
  const msg = JSON.parse(data.toString());
  console.log('Received:', JSON.stringify(msg));

  if (msg.type === 'event' && msg.event === 'connect.challenge') {
    // Try to respond with the nonce
    const nonce = msg.payload.nonce;
    // Maybe we need to sign the nonce with the token
    const response = {
      type: 'connect.response',
      payload: {
        nonce: nonce,
        token: token
      }
    };
    ws.send(JSON.stringify(response));
    console.log('Sent challenge response');
  } else if (msg.type === 'event' && msg.event === 'connect.success') {
    console.log('Authenticated successfully!');
    // Now send the actual message
    const sendMsg = {
      type: 'sessions_send',
      id: '1',
      sessionKey: 'agent:002:main',
      message: '002，有个新流水线任务等你处理。brief已写好：/root/.openclaw-002/workspace/pipeline/brief.md。请读brief，写大纲到 /root/.openclaw-002/workspace/pipeline/outline.md，然后发 sessions_send(sessionKey=\"agent:main:main\") 告知大纲已写好。',
      timeoutSeconds: 300
    };
    ws.send(JSON.stringify(sendMsg));
    console.log('Sent message');
  }
});

ws.on('error', (e) => {
  console.log('Error:', e.message);
  process.exit(1);
});

setTimeout(() => {
  console.log('Timeout');
  ws.close();
  process.exit(0);
}, 10000);
" 2>&1

